mapper.delete:
DELETE FROM board
WHERE no = #{no}
    AND member_no = #{memberNo}

mapper.select:
SELECT b.*, m.member_id, m.name
FROM board b
JOIN member m ON b.member_no = m.no
WHERE 1 = 1


    AND b.board_type = #{searchBoardType}



    AND b.is_deleted = #{searchDeleted}



    AND b.title LIKE '%' || #{keyword} || '%'



    AND m.member_id = #{keyword}


ORDER BY b.no DESC
OFFSET #{offset} ROWS FETCH NEXT #{size} ROWS ONLY

SELECT COUNT(*)
FROM board b
JOIN member m ON b.member_no = m.no
WHERE 1 = 1


    AND b.board_type = #{searchBoardType}



    AND b.is_deleted = #{searchDeleted}



    AND b.title LIKE '%' || #{keyword} || '%'



    AND m.member_id = #{keyword}
